def pigeonhole_sort(arr):
	min_val = min(arr)
	max_val = max(arr)
	size = max_val - min_val + 1
	holes = [0] * size
	for x in arr:
		holes[x - min_val] += 1
	i = 0
	for count in range(size):
		while holes[count] > 0:
			holes[count] -= 1
			arr[i] = count + min_val
			i += 1

Code.JavaScript:
function pigeonholeSort(arr) {
	let min = Math.min(...arr);
	let max = Math.max(...arr);
	let size = max - min + 1;
	let holes = new Array(size).fill(0);
	for (let i = 0; i < arr.length; i++) {
		holes[arr[i] - min]++;
	}
	let i = 0;
	for (let count = 0; count < size; count++) {
		while (holes[count] > 0) {
			holes[count]--;
			arr[i] = count + min;
			i++;
		}
	}
}

