Code.C:
void pigeonholeSort(int arr[], int n) {
	int min = arr[0];
	int max = arr[0];
	for (int i = 1; i < n; i++) {
		if (arr[i] < min) min = arr[i];
		if (arr[i] > max) max = arr[i];
	}
	int size = max - min + 1;
	int *holes = (int *)calloc(size, sizeof(int));
	for (int i = 0; i < n; i++) {
		holes[arr[i] - min]++;
	}
	int i = 0;
	for (int count = 0; count < size; count++) {
		while (holes[count] > 0) {
			holes[count]--;
			arr[i] = count + min;
			i++;
		}
	}
	free(holes);
}
